canEditStaff(member: StaffMember): boolean {
  const isOwner = this.authService.isOwner();
  const currentUserRole = this.authService.getStaffRole();
  const currentUserId = this.authService.currentUserValue?.id;
  
  // Non puoi modificare te stesso
  if (member.user_id === currentUserId) {
    return false;
  }
  
  // Solo il titolare può modificare tutti
  if (isOwner) return true;
  
  // Manager non può modificare altri manager o owner
  if (currentUserRole === 'manager') {
    return member.role !== 'manager';
  }
  
  return false;
}

canRemoveStaff(member: StaffMember): boolean {
  const isOwner = this.authService.isOwner();
  const currentUserRole = this.authService.getStaffRole();
  const currentUserId = this.authService.currentUserValue?.id;
  
  // Non puoi rimuovere te stesso
  if (member.user_id === currentUserId) {
    return false;
  }
  
  // Solo owner può rimuovere tutti
  if (isOwner) {
    return true;
  }
  
  // Manager può rimuovere solo chef, waiter e kitchen_staff
if (currentUserRole === 'manager') {
  return ['chef', 'waiter', 'kitchen_staff', 'social_media_manager'].includes(member.role);
}
  
  return false;
}


private handleError(error: any, defaultMessage: string): void {
  console.error('Staff Management Error:', error);
  
  if (error?.code === '23503') {
    alert('Impossibile completare l\'operazione: esistono dati collegati a questo membro dello staff.');
  } else if (error?.message) {
    alert('Errore: ' + error.message);
  } else {
    alert(defaultMessage);
  }
}

